    29→export const ActionPages = () => {
    30→  const showFullFunctionality = useBreakpointValue({ base: false, md: true }) ?? false;
    31→  const { t } = useTranslation(['actionPages', 'products', 'common']);
    32→  const { actionPagesWrite } = usePermissions();
    33→  const { isLoading: isAccountLoading } = useGetAccount();
    34→
    35→  const {
    36→    isOpen: isTagsDrawerOpen,
    37→    onClose: onCloseTagsDrawer,
    38→    onOpen: onOpenTagsDrawer,
    39→  } = useDisclosure();
    40→  const {
    41→    changeQueryFilter,
    42→    columns,
    43→    data,
    44→    isAllSelected,
    45→    isLoaded,
    46→    isPauseModalOpen,
    47→    isSchedulePauseModalOpen,
    48→    onClosePauseModal,
    49→    onCloseSchedulePauseModal,
    50→    onCreate,
    51→    onOpenPauseModal,
    52→    onOpenSchedulePauseModal,
    53→    pagination,
    54→    queryFilters: { searchTerm },
    55→    selectedRows,
    56→    setSelectedRows,
    57→  } = useActionPages({ onManageTags: onOpenTagsDrawer });
    58→
    59→  const enableTagging = useFeatureFlag('actionPages.tagging');
    60→  const enableEvents = useFeatureFlag('actionPages.events');
    61→  const displayTable = data.length || !isLoaded;
    62→  const displayNoResults = !displayTable && searchTerm;
    63→  const displayEmptyState = !displayTable && !searchTerm;
    64→
    65→  const headerActions = useMemo(
    66→    () => (
    67→      <Flex alignItems="center" flexDirection="row" gap={5}>
    68→        <Label variant="regular">
    69→          {t('actionPages:tableHeaderActions.selected', {
    70→            selectionCount: isAllSelected ? t('common:all') : selectedRows?.length,
    71→          })}
    72→        </Label>
    73→        <Button cursor="pointer" onClick={onOpenSchedulePauseModal} variant="text">
    74→          {t('actionPages:tableHeaderActions.scheduleOnOff')}
    75→        </Button>
    76→        <Button cursor="pointer" onClick={onOpenPauseModal} variant="text">
    77→          {t('actionPages:tableHeaderActions.onOff')}
    78→        </Button>
    79→      </Flex>
    80→    ),
    81→    [isAllSelected, onOpenSchedulePauseModal, onOpenPauseModal, selectedRows?.length, t]
    82→  );
    83→
    84→  if (isAccountLoading) {
    85→    return <Loading />;
    86→  }
    87→
    88→  return (
