   100→            >
   101→              {showFullFunctionality
   102→                ? t('actionPages:button.new.large')
   103→                : t('actionPages:button.new.small')}
   104→            </MenuButton>
   105→          </NoAccessTooltip>
   106→          <MenuList zIndex="popover">
