   111→            >
   112→              {t('actionPages:button.donation')}
   113→            </MenuItem>
   114→            {enableEvents && (
   115→              <MenuItem
   116→                onClick={() => {
   117→                  onCreate(PageTypes.Event);
   118→                }}
   119→              >
   120→                {t('actionPages:button.event')}
   121→              </MenuItem>
   122→            )}
   123→
   124→            <MenuItem
   125→              onClick={() => {
   126→                onCreate(PageTypes.Lead);
   127→              }}
   128→            >
   129→              {t('actionPages:button.lead')}
   130→            </MenuItem>
   131→          </MenuList>
   132→        </Menu>
   133→      }
   134→      views={[]}
   135→    >
   136→      {enableTagging ? (
   137→        <ManageTagsDrawer isOpen={isTagsDrawerOpen} onClose={onCloseTagsDrawer} />
   138→      ) : null}
   139→      <FilterActionsLayout
   140→        actions={
   141→          <HStack alignItems="center" spacing={2}>
   142→            <SharedTableActions onClickTags={enableTagging ? onOpenTagsDrawer : undefined} />
   143→            <FilterDrawer />
   144→          </HStack>
   145→        }
   146→        footer={
   147→          displayTable && (
   148→            <Pagination
   149→              helpPath="https://help.anedot.com/en/articles/9014929-action-pages-index"
   150→              isLoaded={isLoaded}
   151→              {...pagination}
   152→            />
   153→          )
   154→        }
   155→        search={
   156→          <DebouncedInputControl
   157→            defaultValue={searchTerm ?? ''}
   158→            name="searchTerm"
   159→            onChange={(s) => changeQueryFilter('searchTerm', s)}
   160→            placeholder={t('common:search')}
   161→            size="sm"
   162→            type="search"
   163→            variant="filter"
   164→          />
   165→        }
   166→      >
   167→        <BulkSchedulePauseConfirmationModal
   168→          isAllSelected={isAllSelected}
   169→          isOpen={isSchedulePauseModalOpen}
   170→          onClose={onCloseSchedulePauseModal}
   171→          selectedRows={selectedRows}
   172→        />
   173→        {selectedRows && (
   174→          <BulkPauseConfirmationModal
   175→            isAllSelected={isAllSelected}
   176→            isOpen={isPauseModalOpen}
   177→            onClose={onClosePauseModal}
   178→            rowCount={pagination.totalCount}
   179→            selectedRows={selectedRows}
   180→          />
   181→        )}
   182→        {displayTable && (
   183→          <Table
   184→            columns={columns}
   185→            data={data}
   186→            hasSelectableRows
   187→            headerActions={headerActions}
   188→            headerActionsIndex={2}
   189→            isLoaded={isLoaded}
   190→            setSelectedRows={setSelectedRows}
   191→          />
   192→        )}
   193→        {displayNoResults && (
   194→          <EmptyState
   195→            heading={`${t('actionPages:emptySearch.heading')} "${searchTerm}"`}
   196→            Icon={MagnifyIcon}
   197→            subheading={t('actionPages:emptySearch.subheading')}
   198→          />
   199→        )}
   200→        {displayEmptyState && (
   201→          <EmptyState
   202→            heading={t('actionPages:empty.heading')}
   203→            subheading={t('actionPages:empty.subheading')}
   204→          />
   205→        )}
   206→      </FilterActionsLayout>
   207→    </TableLayout>
   208→  );
   209→};
