    40→export const SharePopover = ({ actionPageId, children, defaultSourceCode, slug }: Props) => {
    41→  const { t } = useTranslation('actionPagesBuilder');
    42→  const { currentAccount } = useGetAccount();
    43→  const { customDomains } = useGetAllCustomDomains({});
    44→  const { showToast } = useToast();
    45→  const { user } = useAuthStore();
    46→
    47→  const embedURL = getActionPageURLByString(
    48→    currentAccount?.slug || '',
    49→    actionPageId ?? '',
    50→    customDomains,
    51→    defaultSourceCode
    52→  );
    53→
    54→  const vanityURL = getActionPageURLByString(
    55→    currentAccount?.slug || '',
    56→    slug ?? actionPageId ?? '',
    57→    customDomains,
    58→    defaultSourceCode
    59→  );
    60→
    61→  const { onCopy: onCopyPageURL } = useClipboard(vanityURL);
    62→
    63→  const { onCopy: onCopyEmbedCode } = useClipboard(
    64→    `<iframe src="${embedURL}${
    65→      hasQueryParams(embedURL) ? '&' : '?'
    66→    }embed=true" width="100%" height="100%" frameborder="0"></iframe>`
    67→  );
    68→
    69→  const qrCodeURL = `${embedURL}${
    70→    hasQueryParams(embedURL) ? '&' : '?'
    71→  }utm_source=anedot&utm_medium=qr_code&utm_campaign=${slug}`;
    72→  const isNew = !actionPageId || actionPageId.startsWith('new');
    73→
    74→  return (
    75→    <Popover isLazy>
    76→      {({ isOpen, onClose }) => (
    77→        <>
    78→          {isNew ? (
    79→            <Tooltip hasArrow label="Save the page to share" shouldWrapChildren>
    80→              <Button
    81→                isDisabled
    82→                rightIcon={<ToggleChevron isOpen={false} />}
    83→                variant="secondaryWhite"
    84→              >
    85→                Share
    86→              </Button>
    87→            </Tooltip>
    88→          ) : (
    89→            <PopoverTrigger>{children({ isOpen })}</PopoverTrigger>
    90→          )}
    91→          {isOpen && (
    92→            <Portal>
    93→              <Box
    94→                sx={{
    95→                  // Default is 10, need to increase to be above action pages which itself is a modal
    96→                  '.chakra-popover__popper': {
    97→                    zIndex: 99999,
    98→                  },
    99→                }}
   100→              >
   101→                <PopoverContent
   102→                  border="none"
   103→                  borderColor="transparent"
   104→                  boxShadow="none"
   105→                  outline="none"
   106→                >
   107→                  <Panel
   108→                    borderRadius="2xl"
   109→                    boxShadow="0px 14px 32px rgba(44, 58, 65, 0.15)"
   110→                    minHeight="338px"
   111→                    minWidth="318px"
   112→                    p={6}
   113→                    variant="primary"
   114→                  >
   115→                    <Stack spacing={4}>
   116→                      <Box>
   117→                        <Heading textStyle="H4Regular">{t('shareMenu.title')}</Heading>
   118→                        <Paragraph variant="regular">{t('shareMenu.subTitle')}</Paragraph>
   119→                      </Box>
   120→                      <Button
   121→                        leftIcon={<CopyIcon />}
   122→                        onClick={() => {
   123→                          onCopyPageURL();
   124→                          onClose();
   125→                          showToast({
   126→                            message: t('shareMenu.successLinkCopy'),
   127→                            variant: 'success',
   128→                          });
   129→                        }}
   130→                        size="lg"
   131→                        variant="primary"
   132→                      >
   133→                        {t('shareMenu.copyLink')}
   134→                      </Button>
   135→                      <Button
   136→                        leftIcon={<EmbedCodeIcon />}
   137→                        onClick={() => {
   138→                          onCopyEmbedCode();
   139→                          onClose();
   140→                          showToast({
   141→                            message: t('shareMenu.successEmbedCopy'),
   142→                            variant: 'success',
   143→                          });
   144→                        }}
   145→                        size="lg"
   146→                        variant="secondary"
   147→                      >
   148→                        {t('shareMenu.embed')}
   149→                      </Button>
   150→                      {user?.staffRole ? <CopyToAccountButton onClose={onClose} /> : null}
   151→                      <Panel p={4} variant="secondary">
   152→                        <HStack spacing={4}>
   153→                          <Flex align="center" height="66px" justify="center" width="66px">
   154→                            <Box transform="scale(0.0644)">
   155→                              <QRCodeCanvas
   156→                                id={QR_CODE_ID}
   157→                                imageSettings={{
   158→                                  excavate: false,
   159→                                  height: 128,
   160→                                  src: `${getStaticPath()}images/anedot_icon.png`,
   161→                                  width: 128,
   162→                                }}
   163→                                size={1024}
   164→                                value={qrCodeURL}
   165→                              />
   166→                            </Box>
   167→                          </Flex>
   168→                          <Link
   169→                            onClick={() => downloadCanvasAsPng(QR_CODE_ID)}
   170→                            textStyle="labelMedium"
   171→                          >
   172→                            {t('shareMenu.downloadQr')}
   173→                          </Link>
   174→                        </HStack>
   175→                      </Panel>
   176→                    </Stack>
   177→                  </Panel>
   178→                </PopoverContent>
   179→              </Box>
   180→            </Portal>
   181→          )}
   182→        </>
   183→      )}
   184→    </Popover>
   185→  );
   186→};
