     1→import { Account } from '@domain/account';
     2→import { IActionPage } from '@domain/actionPages';
     3→import { ICustomDomain } from '@domain/customDomains';
     4→import { getBasePaths } from '@ui/utils/getBasePaths';
     5→import { isDevelopment } from '@utils/isDevelopment';
     6→import { isVitePreview } from '@utils/isDevelopment/isVitePreview';
     7→import prependHttp from 'prepend-http';
     8→
     9→const { secureBasePath } = getBasePaths();
    10→
    11→/**
    12→ *
    13→ * custom domain + custom page slug
    14→ * custom domain + page uuid
    15→ * anedot domain + custom account slug + custom page slug
    16→ * anedot domain + account uuid + custom page slug
    17→ * anedot domain + account uid + page uuid
    18→ */
    19→
    20→/**
    21→ * Return the URL for an Action Page associated with a particular Account. Uses the
    22→ * first available custom domain for the Account if available and removes duplicated
    23→ * forward slashes. Assumes we only ever care about the first domain returned.
    24→ */
    25→export const getActionPageURLByString = (
    26→  accountSlug: string,
    27→  actionPageId: string,
    28→  customDomains?: ICustomDomain[],
    29→  defaultSourceCode?: string | null
    30→) => {
    31→  let basePath = `${
    32→    // if it's development or preview, we use the current origin
    33→    isDevelopment() || isVitePreview()
    34→      ? // if it's preview mode, append /uiv2 to the URL so it works right
    35→        window.location.origin + (isVitePreview() ? '/uiv2' : '')
    36→      : secureBasePath
    37→  }/${accountSlug}`;
    38→
    39→  const customDomain = customDomains?.find((domain) => domain.enabled && !!domain.hostname);
    40→  if (customDomain && !(isDevelopment() || isVitePreview())) {
    41→    basePath = prependHttp(customDomain.hostname);
    42→  }
    43→
    44→  const sourceCode = defaultSourceCode
    45→    ? `?source_code=${encodeURIComponent(defaultSourceCode)}`
    46→    : '';
    47→
    48→  return `${basePath}/${actionPageId}${sourceCode}`.replace(/([^:])(\/\/+)/g, '$1/');
    49→};
    50→
    51→/**
    52→ * Return the URL for an Action Page associated with a particular Account. Uses the
    53→ * Account's custom domain if available and removes duplicated forward slashes.
    54→ */
    55→export const getActionPageURL = (
    56→  account: Account | undefined,
    57→  actionPage: IActionPage,
    58→  customDomains?: ICustomDomain[]
    59→) => {
    60→  if (!account) {
    61→    return '';
    62→  }
    63→
    64→  return getActionPageURLByString(
    65→    account.slug,
    66→    actionPage.slug ?? actionPage.id,
    67→    customDomains,
    68→    actionPage.defaultSourceCode
    69→  );
    70→};
