    19→
    20→type Props = {
    21→  getViewHref: (row: IActionPage) => string;
    22→  onActivate: (id: string) => void;
    23→  onArchive: (id: string) => void;
    24→  onClone: (id: string, pageType: ActionPageType) => void;
    25→  onManageTags: () => void;
