    58→      ),
    59→      disableGroupBy: true,
    60→      disableResizing: true,
    61→      Header: '#',
    62→      maxWidth: 50,
    63→      minWidth: 50,
    64→      width: 50,
    65→    }),
    66→    [pageIndex, pageSize]
    67→  );
    68→
    69→  const nameColumn = useMemo<Column<ActionPageTableRow>>(
    70→    () => ({
    71→      accessor: 'name',
    72→      Cell: ({ row, value }) => {
    73→        const isActive = row.original.status === 'active';
    74→        const isArchived = row.original.status === 'archived';
