    76→        return (
    77→          <CellContentWithAction>
    78→            {value}
    79→            {currentAccount ? (
    80→              <ActionMenu
    81→                actions={[
    82→                  {
    83→                    href: getViewHref(row.original),
    84→                    isDisabled: !actionPagesRead,
    85→                    isExternal: true,
    86→                    label: tCommon('button.view'),
    87→                  },
