    29→type ActionPagesBuilderProps = {
    30→  actionPage: ActionPageDetails;
    31→  basePath: string;
    32→  customFields?: ICustomField[];
    33→  featuredTemplate?: Template;
    34→  onApplyFilters: () => void;
