    42→
    43→export const formId = 'action-pages-builder-form';
    44→
    45→const getPanelState = (basePath: string, pathname: string, routes: RouteOption[]) => {
    46→  const activeIndex = routes.findIndex(({ path }) => matchPath(`${basePath}/${path}/*`, pathname));
    47→
    48→  if (activeIndex !== 0) {
    49→    return [1, activeIndex, 0];
    50→  }
    51→
    52→  return [0, 0, 0];
