    54→
    55→export const ActionPagesBuilder = ({
    56→  actionPage,
    57→  basePath,
    58→  customFields,
    59→  featuredTemplate,
    60→  onApplyFilters,
    61→  onClearFilters,
    62→  onUpdateActionPage,
    63→  routes,
    64→  showTemplates,
    65→  templateGroups,
    66→  templates,
    67→}: ActionPagesBuilderProps) => {
    68→  const { currentAccount, keepQueryParamNavigate, navigate, pathname } =
    69→    useActionPagesBuilderNavigation();
    70→  const accountId = currentAccount?.id;
    71→  const containerRef = useRef<HTMLDivElement>(null);
    72→  const searchParams = useQueryParam();
    73→  const { t } = useTranslation(['actionPagesBuilder', 'actionPageSettings', 'actionPageWorkflows']);
    74→
    75→  const [editing, serverError, onPostPublish, onPrePublish] = useConfigurationStore((state) => [
    76→    state.editing,
    77→    state.error,
    78→    state.onPostPublish,
    79→    state.onPrePublish,
    80→  ]);
    81→
    82→  const schema: ActionPagesBuilderSchema = useMemo(
    83→    () => actionPagesBuilderSchema(t, { customFields, editingConfiguration: editing?.key }),
    84→    [t, customFields, editing?.key]
    85→  );
    86→
    87→  const isOnNoSubRoute = useMatch('/accounts/:accountId/action_pages/:actionPageId/edit');
    88→  const { changeQueryFilter: changeTemplateQueryFilter, queryFilters: templateQueryFilters } =
    89→    useQueryFilters<TemplateQueryFilter>('q', 'type', 'category', 'layout', 'onlyFavorites');
    90→
    91→  /** currentSubPage is used within the setOption function for correctly animating between sub panels */
    92→  const [[currentPage, currentSubPage, direction], setCurrentPage] = useState(
    93→    getPanelState(basePath, pathname, routes)
    94→  );
    95→
    96→  // Prevent enter key in any form input from submitting the form
    97→  useEffect(() => {
    98→    const handler = (e: KeyboardEvent) => {
    99→      if (e.keyCode === 13 && (e.target as HTMLElement)?.tagName !== 'TEXTAREA') {
   100→        e.preventDefault();
