   110→    if (showTemplates && newOption === 0) {
   111→      setCurrentPage(([page]) => [0, 0, newOption - page]);
   112→    } else {
   113→      setCurrentPage(([_, subPage]) => [1, newOption, newOption - subPage]);
   114→    }
