   119→  /** go back to the main action pages index */
   120→  const onBack = () => {
   121→    keepQueryParamNavigate(
   122→      generatePath('/accounts/:accountId/action_pages', {
   123→        accountId: accountId as string,
   124→      })
   125→    );
   126→  };
   127→
   128→  const onSubmit = useCallback(
   129→    async (
   130→      _values: ActionPageDetailFormValues,
   131→      { getValues, reset }: UseFormReturn<ActionPageDetailFormValues, object>
   132→    ) => {
