   134→
   135→      if (onUpdateActionPage) {
   136→        const updates = getValues();
   137→
   138→        const request = mapActionPageDetailFormValuesToDetails(
   139→          JSON.parse(JSON.stringify(updates)) as ActionPageDetailFormValues
   140→        );
   141→
   142→        const apDetails = await onUpdateActionPage({
   143→          ...request,
   144→          pageType: updates.pageType,
   145→        });
   146→
   147→        await onPostPublish?.();
   148→
   149→        // navigate to new url once returned
   150→        navigate(
   151→          `/${pathname.replace(`/new/`, `/${apDetails.id}/`)}?${searchParams.toString()}`.replace(
   152→            /\/\//g,
   153→            '/'
   154→          ),
   155→          { replace: true, state: null }
   156→        );
   157→
   158→        reset({
   159→          // Keep all the configurations the same
   160→          ...Object.fromEntries(
   161→            Object.entries(updates).filter(([key]) => key.endsWith('Configuration'))
   162→          ),
   163→          // Set the new values for the rest of the AP from the server response
   164→          ...mapActionPageDetailsToFormValues(apDetails, updates.customFields),
